import{_ as e,a as i}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as t,o,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Dostęp WebDAV do strony (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Safety/webdav-site-access.md","filePath":"pl-PL/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),d={name:"pl-PL/Safety/webdav-site-access.md"};function s(r,a,p,u,c,z){return o(),n("div",null,[...a[0]||(a[0]=[l('<h1 id="dostep-webdav-do-strony-beta" tabindex="-1">Dostęp WebDAV do strony (Beta) <a class="header-anchor" href="#dostep-webdav-do-strony-beta" aria-label="Permalink to &quot;Dostęp WebDAV do strony (Beta)&quot;">​</a></h1><p>Ustawienie WebDAV w Ustawieniach bezpieczeństwa udostępnia Twoją stronę ImgBed jako endpoint WebDAV.</p><p>Po włączeniu możesz używać Windows, macOS, mobilnych menedżerów plików lub dowolnego klienta zgodnego z WebDAV do przeglądania, przesyłania, usuwania i zarządzania plikami ImgBed jak zdalnym katalogiem.</p><p>To wejście WebDAV strony. Różni się od kanału przechowywania WebDAV w Ustawieniach przesyłania. Kanał uploadu zapisuje pliki w zewnętrznej usłudze WebDAV. To ustawienie sprawia, że Twoja strona ImgBed sama udostępnia dostęp WebDAV klientom.</p><h2 id="gdzie-skonfigurowac" tabindex="-1">Gdzie skonfigurować <a class="header-anchor" href="#gdzie-skonfigurowac" aria-label="Permalink to &quot;Gdzie skonfigurować&quot;">​</a></h2><p>Otwórz panel administracyjny, a następnie przejdź do:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Dostępne ustawienia:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="co-robi-ta-funkcja" tabindex="-1">Co robi ta funkcja <a class="header-anchor" href="#co-robi-ta-funkcja" aria-label="Permalink to &quot;Co robi ta funkcja&quot;">​</a></h2><p>Po włączeniu WebDAV ImgBed udostępnia stały URL dostępu:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Użyj tego URL-a, aby połączyć się z katalogiem plików ImgBed.</p><p>Dobre zastosowania:</p><ul><li>przeglądanie plików ImgBed bezpośrednio z menedżera plików komputera.</li><li>przeciąganie obrazów do katalogu WebDAV, aby je przesłać.</li><li>organizowanie katalogów ImgBed z lokalnego menedżera plików.</li><li>użycie oprogramowania zgodnego z WebDAV do synchronizacji lub zarządzania obrazami.</li><li>dostęp do treści ImgBed bez otwierania panelu administracyjnego.</li></ul><h2 id="ustawienia" tabindex="-1">Ustawienia <a class="header-anchor" href="#ustawienia" aria-label="Permalink to &quot;Ustawienia&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Włącza endpoint WebDAV.</p><p>Gdy jest wyłączony, klienci nie mogą łączyć się przez WebDAV.</p><h3 id="username-i-password" tabindex="-1">Username i Password <a class="header-anchor" href="#username-i-password" aria-label="Permalink to &quot;Username i Password&quot;">​</a></h3><p>Tych danych używają klienci WebDAV podczas połączenia.</p><p>Użyj osobnej nazwy użytkownika i hasła dla WebDAV. Nie używaj ponownie hasła administratora ani hasła uploadu.</p><p>Jeśli nazwa użytkownika lub hasło są puste, klienci WebDAV nie połączą się poprawnie.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode określa, który URL obrazu preferują klienci WebDAV przy odczycie.</p><p>Typowe opcje:</p><table tabindex="0"><thead><tr><th>Tryb</th><th>Opis</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed wybiera według kontekstu. Zalecane do normalnego użycia.</td></tr><tr><td>Original</td><td>Preferuje oryginalne obrazy.</td></tr><tr><td>Thumbnail</td><td>Preferuje miniatury. Przydatne do szybkiego podglądu.</td></tr></tbody></table><p>Jeśli nie masz pewności, zostaw <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Domyślny kanał jest używany do uploadów WebDAV.</p><p>Gdy kopiujesz pliki do katalogu WebDAV z Windows lub innego klienta, ImgBed przesyła je przez wybrany domyślny kanał uploadu.</p><p>Jeśli domyślny kanał nie jest wybrany, przeglądanie może działać, ale upload może się nie udać.</p><h2 id="dostep-webdav-w-windows-11" tabindex="-1">Dostęp WebDAV w Windows 11 <a class="header-anchor" href="#dostep-webdav-w-windows-11" aria-label="Permalink to &quot;Dostęp WebDAV w Windows 11&quot;">​</a></h2><p>Windows 11 może dodać WebDAV jako lokalizację sieciową.</p><ol><li>Otwórz <code>This PC</code>.</li><li>Wybierz <code>Add a network location</code>.</li><li>Wpisz <code>https://your-domain.com/dav</code>.</li><li>Po wyświetleniu prośby wpisz nazwę użytkownika i hasło WebDAV.</li><li>Zakończ kreatora. Katalog WebDAV będzie można otworzyć w File Explorer.</li></ol><p><img src="'+e+'" alt="Dodawanie WebDAV w Windows 11" loading="lazy"></p><p>Po dodaniu katalog WebDAV pojawi się w Eksploratorze plików Windows. Możesz otwierać, kopiować i zarządzać plikami jak w zwykłym katalogu.</p><p><img src="'+i+'" alt="WebDAV w Windows" loading="lazy"></p><h2 id="obsługiwane-operacje" tabindex="-1">Obsługiwane operacje <a class="header-anchor" href="#obsługiwane-operacje" aria-label="Permalink to &quot;Obsługiwane operacje&quot;">​</a></h2><p>Po udanym połączeniu WebDAV zwykle możesz:</p><ul><li>przeglądać pliki i katalogi.</li><li>przesyłać pliki.</li><li>tworzyć katalogi.</li><li>zmieniać nazwy plików lub katalogów.</li><li>przenosić pliki.</li><li>usuwać pliki.</li></ul><p>WebDAV najlepiej sprawdza się do codziennego dostępu i lekkiego zarządzania plikami. Do dużych przenosin, masowego usuwania albo złożonej organizacji użyj panelu administracyjnego.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Udane połączenia WebDAV pojawiają się też na karcie WebDAV w Login Device Management.</p><p>Możesz tam sprawdzać klientów WebDAV i wymuszać wylogowanie starych urządzeń.</p><p>Jeśli zmienisz nazwę użytkownika lub hasło WebDAV, stare klienty muszą zalogować się ponownie.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-ciagle-pyta-o-nazwe-uzytkownika-i-hasło" tabindex="-1">Windows ciągle pyta o nazwę użytkownika i hasło <a class="header-anchor" href="#windows-ciagle-pyta-o-nazwe-uzytkownika-i-hasło" aria-label="Permalink to &quot;Windows ciągle pyta o nazwę użytkownika i hasło&quot;">​</a></h3><p>Sprawdź:</p><ul><li>URL to <code>https://your-domain.com/dav</code>.</li><li>Nazwa użytkownika i hasło zgadzają się z ustawieniami WebDAV.</li><li>WebDAV jest włączony.</li><li>Strona jest dostępna przez HTTPS.</li></ul><h3 id="przegladanie-działa-ale-upload-nie" tabindex="-1">Przeglądanie działa, ale upload nie <a class="header-anchor" href="#przegladanie-działa-ale-upload-nie" aria-label="Permalink to &quot;Przeglądanie działa, ale upload nie&quot;">​</a></h3><p>Sprawdź <code>Default channel</code>.</p><p>Upload WebDAV wymaga domyślnego kanału przesyłania. Jeśli go nie ma, jest wyłączony lub źle skonfigurowany, upload może się nie udać.</p><h3 id="szybkosc-dostepu-jest-niestabilna" tabindex="-1">Szybkość dostępu jest niestabilna <a class="header-anchor" href="#szybkosc-dostepu-jest-niestabilna" aria-label="Permalink to &quot;Szybkość dostępu jest niestabilna&quot;">​</a></h3><p>Wydajność WebDAV zależy od klienta, sieci, liczby plików i domyślnego kanału uploadu.</p><p>Jeśli katalog ma dużo plików, uporządkuj je w podkatalogach zamiast trzymać zbyt wiele w jednym miejscu.</p><h2 id="zalecenia-bezpieczenstwa" tabindex="-1">Zalecenia bezpieczeństwa <a class="header-anchor" href="#zalecenia-bezpieczenstwa" aria-label="Permalink to &quot;Zalecenia bezpieczeństwa&quot;">​</a></h2><ul><li>Używaj HTTPS dla dostępu WebDAV.</li><li>Ustaw silne hasło.</li><li>Nie udostępniaj hasła WebDAV osobom niezaufanym.</li><li>Wyłącz WebDAV, gdy go nie używasz.</li><li>Okresowo czyść nieużywane urządzenia WebDAV w Login Device Management.</li></ul><h2 id="rozmiar-pliku-przy-uploadzie-webdav" tabindex="-1">Rozmiar pliku przy uploadzie WebDAV <a class="header-anchor" href="#rozmiar-pliku-przy-uploadzie-webdav" aria-label="Permalink to &quot;Rozmiar pliku przy uploadzie WebDAV&quot;">​</a></h2><p>Klienci WebDAV nie używają przeglądarkowego mechanizmu uploadu częściowego ze strony uploadu. Dla plików powyżej poniższych zalecanych limitów użyj strony web uploadu.</p><table tabindex="0"><thead><tr><th>Domyślny kanał uploadu</th><th style="text-align:right;">Zalecany limit jednego pliku WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const h=t(d,[["render",s]]);export{g as __pageData,h as default};
